import React from 'react';
import { Link } from 'react-router-dom';

function Footer() {
  return (
    <footer style={{ background: '#0a0a0a', borderTop: '2px solid #00aa00', padding: '40px 50px', textAlign: 'center' }}>
      <img src="/logo.png" alt="logo" style={{ width: '70px', height: '70px', borderRadius: '50%', border: '2px solid #00aa00', marginBottom: '15px' }} />
      <p style={{ color: '#ffd700', fontSize: '22px', fontWeight: 'bold', marginBottom: '15px' }}>BBRS Morphix IT</p>
      <ul style={{ display: 'flex', justifyContent: 'center', gap: '30px', listStyle: 'none', marginBottom: '20px', padding: 0 }}>
        {[['/', 'Accueil'],['/services','Services'],['/apropos','À propos'],['/blog','Blog'],['/contact','Contact']].map(([path, label]) => (
          <li key={path}><Link to={path} style={{ color: '#aaaaaa', textDecoration: 'none', fontSize: '14px' }}>{label}</Link></li>
        ))}
      </ul>
      <p style={{ color: '#555555', fontSize: '13px', marginBottom: '5px' }}>© 2026 BBRS Morphix IT — Tous droits réservés</p>
      <p style={{ color: '#00aa00', fontSize: '14px', letterSpacing: '2px' }}>Renaître. Connecter. Sécuriser.</p>
    </footer>
  );
}

export default Footer;
